export const getSOPRecords = (): SOPRecord[] => {
  const stored = localStorage.getItem('garmentqms_sops');
  let records: SOPRecord[] = [];
  
  if (stored) {
    records = JSON.parse(stored);
    // Auto-merge any newly added mock SOPs that aren't in localStorage yet
    const existingIds = new Set(records.map(r => r.id));
    const newlyAddedMocks = MOCK_SOPS.filter(m => !existingIds.has(m.id));
    
    if (newlyAddedMocks.length > 0) {
      records = [...records, ...newlyAddedMocks];
      localStorage.setItem('garmentqms_sops', JSON.stringify(records));
    }
  } else {
    records = MOCK_SOPS;
    localStorage.setItem('garmentqms_sops', JSON.stringify(records));
  }
  
  return records;
};

export const saveSOPRecords = (records: SOPRecord[]) => {
  localStorage.setItem('garmentqms_sops', JSON.stringify(records));
  // Background dump to Dexie for relational linking
  if (records.length > 0) {
    db.sops.clear().then(() => {
      // @ts-ignore
      db.sops.bulkAdd(records).catch(e => console.error("Dexie push failed", e));
    });
  } else {
    db.sops.clear();
  }
};
